import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Use nextLine() to read entire line

        // Assuming input size is limited to 10 characters
        char[] buffer = new char[10];

        // Copying input into buffer with proper bounds checking
        for (int i = 0; i < input.length() && i < buffer.length; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Input copied successfully.");
    }
}

